import subprocess
import shlex


def get_last_login_records(username: str) -> str:
    """
    Query the recent login records for a specified user.

    Args:
        username: The username whose login records are to be queried, e.g., 'alice'.

    Returns:
        The raw text of the user's recent login records.
    """
    # Build command safely to prevent shell injection
    # Use separate commands for 'last' and 'grep' to avoid shell piping
    try:
        # First, get the full login history
        last_result = subprocess.run(
            ['last'],
            capture_output=True,
            text=True,
            check=False  # Don't raise exception on non-zero exit
        )

        if last_result.returncode != 0:
            # Return error message if 'last' command fails
            return f"Error executing 'last' command: {last_result.stderr}"

        # Then filter the results for the specific username
        if not last_result.stdout:
            return "No login records found"

        # Filter lines containing the username
        filtered_lines = []
        for line in last_result.stdout.splitlines():
            if username in line:
                filtered_lines.append(line)

        # Return filtered results
        if filtered_lines:
            return '\n'.join(filtered_lines)
        else:
            return f"No login records found for user '{username}'"

    except FileNotFoundError:
        return "Error: 'last' command not found on this system"
    except Exception as e:
        return f"Unexpected error: {str(e)}"
